module RefModule(
    input clk,
    input rst,
    input [3:0] data_in,
    output [3:0] data_out
    );reg [3:0] unused_data_reg;

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            unused_data_reg <= 4'd0;
        end
        else begin
            unused_data_reg <= data_in;
        end
    end

    assign data_out = unused_data_reg;

endmodule
